let tableNo = 0;
let figureNo = 0;
const html = [];

function e(value) {
  return String(value)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll("\"", "&quot;");
}

function src(file) {
  return `file:///${file.replaceAll("\\", "/").replaceAll(" ", "%20")}`;
}

function raw(value) {
  html.push(value);
}

function p(value, cls = "") {
  html.push(`<p${cls ? ` class="${cls}"` : ""}>${value}</p>`);
}

function h1(value) {
  html.push(`<h1>${e(value)}</h1>`);
}

function h2(value) {
  html.push(`<h2>${e(value)}</h2>`);
}

function h3(value) {
  html.push(`<h3>${e(value)}</h3>`);
}

function table(title, headers, rows) {
  tableNo += 1;
  p(`Таблица ${tableNo} - ${e(title)}`, "table-title");
  raw("<table>");
  raw(`<thead><tr>${headers.map((header) => `<th>${e(header)}</th>`).join("")}</tr></thead>`);
  raw("<tbody>");
  for (const row of rows) {
    raw(`<tr>${row.map((cell) => `<td>${cell}</td>`).join("")}</tr>`);
  }
  raw("</tbody></table>");
}

function figure(file, title, width = "16.5cm") {
  figureNo += 1;
  raw(`<div class="figure"><img src="${src(file)}" style="width:${width}; max-width:100%;" alt="${e(title)}"></div>`);
  p(`Рисунок ${figureNo} - ${e(title)}`, "fig-title");
}

function bullet(items) {
  raw("<ul>");
  for (const item of items) raw(`<li>${item}</li>`);
  raw("</ul>");
}

function pageBreak() {
  raw('<div class="page-break"></div>');
}

function joinSentences(parts) {
  return parts.filter(Boolean).join(" ");
}

function longAnalysis(subject, points) {
  for (const point of points) {
    p(`${subject} ${point}`);
  }
}

